form:Form.form:Scripts:
		function duplicate()
{
	if (Ctrl('grdfichadas').TotalRowsCount() !=0)
	{
		var per = Ctrl('grdfichadas').GetCellSelectedXValue('oi_personal_emp');
		var fecha = Ctrl('grdfichadas').GetCellSelectedXValue('f_fechahora');		
		var tipo = Ctrl('grdfichadas').GetCellSelectedXValue('c_tipo');
		var terminal = Ctrl('grdfichadas').GetCellSelectedXValue('oi_terminal');		

		Ctrl('grdfichadas').AddNew();

		var objctrl = Ctrl('grdfichadas').GetCellSelectedControl('oi_personal_emp');
		objctrl.SetXValue(per);		
		objctrl = Ctrl('grdfichadas').GetCellSelectedControl('f_fechahora');
		objctrl.SetXValue(fecha);
		objctrl = Ctrl('grdfichadas').GetCellSelectedControl('c_tipo');
		objctrl.SetXValue(tipo);
		objctrl = Ctrl('grdfichadas').GetCellSelectedControl('oi_terminal');
		objctrl.SetXValue(terminal);		
	}	
}

function Validate()
{	
	if(Ctrl('PosEditFic').GetXValue() == "" && Ctrl('PreEditFic').GetXValue())
		return true

	momentoActual = new Date();	
	fechaComparePos = new Date(momentoActual.getFullYear(), momentoActual.getMonth(), momentoActual.getDate() + 1 +  parseInt(Ctrl('PosEditFic').GetXValue()));
	fechaComparePre = new Date(momentoActual.getFullYear(), momentoActual.getMonth(), momentoActual.getDate() - 1 - parseInt(Ctrl('PreEditFic').GetXValue()));

	if(Ctrl('PosEditFic').GetXValue() != "")
	{
		for (i=0;i<Ctrl('grdfichadas').TotalRowsCount();i++)	
		{
			if (Ctrl('grdfichadas').GetCellControl("f_fechahora", i).TypedValue() > fechaComparePos) 
			{
				alert('La fecha de la fichada supera la cantidad de días posteriores a la fecha actual permitidos ('+Ctrl('PosEditFic').GetXValue()+').');			
				return false;
			}		 		
		}
	}

	if(Ctrl('PreEditFic').GetXValue() != "")
	{
		for (i=0;i<Ctrl('grdfichadas').TotalRowsCount();i++)	
		{
			if (Ctrl('grdfichadas').GetCellControl("f_fechahora", i).TypedValue() < fechaComparePre) 
			{
				alert('La fecha de la fichada supera la cantidad de días previos a la fecha actual permitidos ('+Ctrl('PreEditFic').GetXValue()+').');
				return false;
			}		 		
		}
	}

	return true;	
}
